# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from functools import wraps
import time
import logging
from typing import Dict, Any, List
import os

app = Flask(__name__)

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

es_host = os.getenv('ELASTICSEARCH_HOST', 'localhost')
es_port = int(os.getenv('ELASTICSEARCH_PORT', 9200))
es_index = os.getenv('ELASTICSEARCH_INDEX', 'products')

es = Elasticsearch([{'host': es_host, 'port': es_port, 'scheme': 'http'}])

CACHE = {}
CACHE_TTL = 300

def cache_response(ttl=CACHE_TTL):
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            cache_key = request.url
            now = time.time()
            
            if cache_key in CACHE:
                cached_data, timestamp = CACHE[cache_key]
                if now - timestamp < ttl:
                    logger.info(f"Cache hit for: {cache_key}")
                    return cached_data
            
            result = f(*args, **kwargs)
            CACHE[cache_key] = (result, now)
            
            return result
        return wrapper
    return decorator

def build_search_query(keyword: str, page: int = 1, page_size: int = 20) -> Dict[str, Any]:
    from_offset = (page - 1) * page_size
    
    query = {
        "from": from_offset,
        "size": page_size,
        "query": {
            "bool": {
                "should": [
                    {
                        "multi_match": {
                            "query": keyword,
                            "fields": ["name^3", "description^2", "category", "brand", "tags"],
                            "type": "best_fields",
                            "fuzziness": "AUTO"
                        }
                    },
                    {
                        "match_phrase": {
                            "name": {
                                "query": keyword,
                                "boost": 5
                            }
                        }
                    }
                ],
                "filter": {
                    "term": {
                        "active": True
                    }
                }
            }
        },
        "highlight": {
            "fields": {
                "name": {},
                "description": {}
            },
            "pre_tags": ["<mark>"],
            "post_tags": ["</mark>"]
        },
        "sort": [
            "_score",
            {"popularity": {"order": "desc"}},
            {"created_at": {"order": "desc"}}
        ],
        "_source": ["id", "name", "description", "price", "currency", "image_url", "category", "brand", "rating", "stock", "popularity"]
    }
    
    return query

def format_search_results(es_response: Dict[str, Any]) -> Dict[str, Any]:
    hits = es_response.get('hits', {})
    total = hits.get('total', {})
    
    if isinstance(total, dict):
        total_count = total.get('value', 0)
    else:
        total_count = total
    
    products = []
    for hit in hits.get('hits', []):
        product = hit.get('_source', {})
        product['score'] = hit.get('_score', 0)
        
        if 'highlight' in hit:
            product['highlights'] = hit['highlight']
        
        products.append(product)
    
    return {
        'total': total_count,
        'products': products
    }

@app.route('/api/search', methods=['GET'])
@cache_response(ttl=300)
def search_products():
    try:
        keyword = request.args.get('q', '').strip()
        
        if not keyword:
            return jsonify({
                'error': 'Missing required parameter: q',
                'message': 'Please provide a search keyword'
            }), 400
        
        if len(keyword) < 2:
            return jsonify({
                'error': 'Invalid search query',
                'message': 'Search keyword must be at least 2 characters'
            }), 400
        
        page = request.args.get('page', 1, type=int)
        page_size = request.args.get('page_size', 20, type=int)
        
        if page < 1:
            page = 1
        if page_size < 1 or page_size > 100:
            page_size = 20
        
        logger.info(f"Searching for: {keyword}, page: {page}, page_size: {page_size}")
        
        query = build_search_query(keyword, page, page_size)
        
        start_time = time.time()
        response = es.search(index=es_index, body=query)
        search_time = time.time() - start_time
        
        logger.info(f"Elasticsearch query took {search_time:.3f}s")
        
        results = format_search_results(response)
        
        return jsonify({
            'success': True,
            'query': keyword,
            'page': page,
            'page_size': page_size,
            'total': results['total'],
            'count': len(results['products']),
            'search_time': round(search_time, 3),
            'results': results['products']
        }), 200
        
    except Exception as e:
        logger.error(f"Search error: {str(e)}", exc_info=True)
        return jsonify({
            'error': 'Internal server error',
            'message': 'An error occurred while processing your search'
        }), 500

@app.route('/api/health', methods=['GET'])
def health_check():
    try:
        es.ping()
        return jsonify({
            'status': 'healthy',
            'elasticsearch': 'connected'
        }), 200
    except Exception as e:
        logger.error(f"Health check failed: {str(e)}")
        return jsonify({
            'status': 'unhealthy',
            'elasticsearch': 'disconnected'
        }), 503

@app.errorhandler(404)
def not_found(e):
    return jsonify({
        'error': 'Not found',
        'message': 'The requested endpoint does not exist'
    }), 404

@app.errorhandler(500)
def internal_error(e):
    return jsonify({
        'error': 'Internal server error',
        'message': 'An unexpected error occurred'
    }), 500

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000, threaded=True)